function solve(nums) {
    const n = nums.length;
    const sortedNums = [...nums].sort((a, b) => a - b);
    let totalSum = 0;

    // 1. Find all divisors k of n
    const divisors = [];
    for (let k = 1; k <= n; k++) {
        if (n % k === 0) {
            divisors.push(k);
        }
    }

    // Helper function to check if a single array can be sorted by cyclic shift
    // A sequence of length k can be sorted into the target sequence T if and only if
    // the set of elements in the sequence is the same as the set of elements in the target subsequence,
    // AND if they are the same set of elements, one must be a cyclic shift of the other.
    // Since the operation is "cycle shift any number of times", any permutation that can be reached by
    // cyclic shifts must be checked.
    // For an array of length k, all reachable states are just the k cyclic shifts of the initial array.
    const isCyclicPermutation = (arr, target) => {
        const k = arr.length;
        if (k === 0) return true;

        // Check if the element counts are the same (necessary condition)
        const arrCounts = new Map();
        const targetCounts = new Map();
        for (const x of arr) arrCounts.set(x, (arrCounts.get(x) || 0) + 1);
        for (const x of target) targetCounts.set(x, (targetCounts.get(x) || 0) + 1);

        for (const [key, count] of arrCounts.entries()) {
            if (targetCounts.get(key) !== count) return false;
        }

        // Check if target is a cyclic shift of arr
        const arrStr = arr.join(',');
        const targetStr = target.join(',');
        const doubledArrStr = arrStr + ',' + arrStr.substring(1);

        // Convert comma-separated strings back to arrays for easier comparison if necessary,
        // but since we are dealing with specific elements, we can use string matching on the joined version.
        // However, direct array comparison after potential rotation is cleaner.

        for (let start = 0; start < k; start++) {
            let rotated = [];
            for (let i = 0; i < k; i++) {
                rotated.push(arr[(start + i) % k]);
            }
            let match = true;
            for (let i = 0; i < k; i++) {
                if (rotated[i] !== target[i]) {
                    match = false;
                    break;
                }
            }
            if (match) return true;
        }

        return false;
    };


    for (const k of divisors) {
        if (k === 1) {
            // For k=1, each sub-array has one element, no movement possible.
            // It can only sort if the original array is already sorted.
            if (nums.join(',') === sortedNums.join(',')) {
                totalSum += k;
            }
            continue;
        }

        // If k > 1, we check the condition
        let canSort = true;
        const numSubarrays = n / k;

        // 1. Determine the target segments (the segments in sortedNums)
        // targetSegments[i] is the target array for the i-th block of size k
        const targetSegments = [];
        for (let i = 0; i < numSubarrays; i++) {
            const start = i * k;
            const end = start + k;
            targetSegments.push(sortedNums.slice(start, end));
        }

        // 2. Check each block
        for (let i = 0; i < numSubarrays; i++) {
            const blockStart = i * k;
            const currentBlock = nums.slice(blockStart, blockStart + k);
            const targetBlock = targetSegments[i];

            // The condition is: The current block must be a cyclic permutation of the target block.
            if (!isCyclicPermutation(currentBlock, targetBlock)) {
                canSort = false;
                break;
            }
        }

        if (canSort) {
            totalSum += k;
        }
    }

    return totalSum;
}

