import scala.collection.mutable

object Solution {
  def solve(nums: Array[Long]): Long = {
    val n = nums.length
    val sortedNums = nums.sorted.map(_.toLong).toArray

    var totalSum: Long = 0

    // Helper function to check if target is a cyclic shift of arr
    // Since we are dealing with Longs, we represent them as strings for easy comparison in the doubled array logic
    def isCyclicPermutation(arr: Array[Long], target: Array[Long]): Boolean = {
      val k = arr.length
      if (k == 0) return true

      // Necessary condition: element counts must match.
      val arrCounts = mutable.HashMap[Long, Int]()
      for (x <- arr) arrCounts(x) = arrCounts.getOrElse(x, 0) + 1

      val targetCounts = mutable.HashMap[Long, Int]()
      for (x <- target) targetCounts(x) = targetCounts.getOrElse(x, 0) + 1

      if (arrCounts != targetCounts) return false

      // Check if target is a cyclic shift of arr
      // This is equivalent to checking if target is a substring of arr concatenated with itself (if we treat them as sequences)
      // Since k is small enough (up to 10^5, but k is a divisor, so this check is O(k^2) worst case, or O(k) with string matching, but k is small enough for simple rotation)
      for (start <- 0 until k) {
        var matchFound = true
        for (i <- 0 until k) {
          val arrIndex = (start + i) % k
          if (arr(arrIndex) != target(i)) {
            matchFound = false
            break
          }
        }
        if (matchFound) return true
      }
      false
    }

    // 1. Find all divisors k of n
    val divisors = mutable.ArrayBuffer[Int]()
    for (k <- 1 to n) {
      if (n % k == 0) {
        divisors += k
      }
    }

    for (k <- divisors) {
      if (k == 1) {
        // For k=1, each sub-array has one element. It can only sort if the original array is already sorted.
        var isAlreadySorted = true
        for (i <- 0 until n - 1) {
          if (nums(i) > nums(i+1)) {
            isAlreadySorted = false
            break
          }
        }
        if (isAlreadySorted) {
          totalSum += k.toLong
        }
        continue
      }

      // If k > 1, we check the condition
      var canSort = true
      val numSubarrays = n / k

      // 1. Determine the target segments (the segments in sortedNums)
      // targetSegments[i] is the target array for the i-th block of size k
      val targetSegments = mutable.ArrayBuffer[Array[Long]]()
      for (i <- 0 until numSubarrays) {
        val start = i * k
        val end = start + k
        val targetBlock = sortedNums.slice(start, end)
        targetSegments += targetBlock
      }

      // 2. Check each block
      for (i <- 0 until numSubarrays) {
        val blockStart = i * k
        // Extract the current block from nums
        val currentBlock = nums.slice(blockStart, blockStart + k)
        val targetBlock = targetSegments(i)

        // The condition is: The current block must be a cyclic permutation of the target block.
        if (!isCyclicPermutation(currentBlock, targetBlock)) {
          canSort = false
          break
        }
      }

      if (canSort) {
        totalSum += k.toLong
      }
    }

    totalSum
  }
}
